import { useState, useEffect } from 'react';
import { Spinner, Modal, Btn, Badge, useToast } from '../../components/shared/index.jsx';
import { getJobs, getJobRanking, uploadAndRankCVs } from '../../api/index.js';

export function HRCVRankingPage() {
  const toast = useToast();

  const [jobs, setJobs]           = useState([]);
  const [selectedJob, setSelectedJob] = useState(null);
  const [rankings, setRankings]   = useState([]);
  const [loading, setLoading]     = useState(false);
  const [rankingLoading, setRankingLoading] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState([]);

  useEffect(() => {
    loadJobs();
  }, []);

  const loadJobs = async () => {
    setLoading(true);
    try {
      const data = await getJobs();
      setJobs(data);
    } catch (err) {
      toast('Failed to load jobs', 'error');
    }
    setLoading(false);
  };

  const handleFileChange = (e) => {
    setUploadedFiles(Array.from(e.target.files));
  };

  const handleRankCVs = async () => {
    if (!selectedJob) {
      toast('Please select a job', 'error');
      return;
    }

    setRankingLoading(true);
    try {
      let data;
      if (uploadedFiles.length > 0) {
        // Upload and rank new CVs
        const formData = new FormData();
        uploadedFiles.forEach(file => formData.append('cvs', file));
        data = await uploadAndRankCVs(selectedJob.id, formData);
      } else {
        // Rank existing submissions
        data = await getJobRanking(selectedJob.id);
      }
      setRankings(data);
    } catch (err) {
      toast('Failed to rank CVs', 'error');
    }
    setRankingLoading(false);
  };

  return (
    <div style={{ maxWidth: 1280, margin: '0 auto', padding: '40px 32px 80px' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 28, flexWrap: 'wrap', gap: 16 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 700, marginBottom: 4 }}>CV Ranking & Analysis</h2>
          <p style={{ fontSize: 13.5, color: 'var(--gray-500)' }}>AI-powered candidate evaluation using semantic analysis and skill matching</p>
        </div>
      </div>

      {/* Job Selection Card */}
      <div style={{ background: 'var(--white)', borderRadius: 20, padding: '24px', border: '1px solid #EAECF0', marginBottom: 24 }}>
        <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 16, color: 'var(--gray-900)' }}>Select Job Position</h3>

        <div style={{ marginBottom: 16 }}>
          <label style={{ display: 'block', fontSize: 12, fontWeight: 700, color: 'var(--gray-700)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.06em' }}>
            Job Position
          </label>
          <select
            value={selectedJob?.id || ''}
            onChange={(e) => {
              const job = jobs.find(j => j.id == e.target.value);
              setSelectedJob(job);
              setRankings([]);
              setUploadedFiles([]);
            }}
            style={{
              width: '100%', padding: '11px 14px', background: 'var(--gray-100)',
              border: '2px solid transparent', borderRadius: 12, fontSize: 13.5,
              outline: 'none', fontFamily: 'var(--sans)', color: 'var(--gray-900)',
            }}
          >
            <option value="">Choose a job position...</option>
            {jobs.map(job => (
              <option key={job.id} value={job.id}>{job.title}</option>
            ))}
          </select>
        </div>

        {/* File Upload */}
        <div style={{ marginBottom: 20 }}>
          <label style={{ display: 'block', fontSize: 12, fontWeight: 700, color: 'var(--gray-700)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.06em' }}>
            Upload Additional CVs (Optional)
          </label>
          <input
            type="file"
            multiple
            accept=".pdf,.txt"
            onChange={handleFileChange}
            style={{
              width: '100%', padding: '11px 14px', background: 'var(--gray-100)',
              border: '2px solid transparent', borderRadius: 12, fontSize: 13.5,
              outline: 'none', fontFamily: 'var(--sans)', color: 'var(--gray-900)',
            }}
          />
          <p style={{ fontSize: 12, color: 'var(--gray-500)', marginTop: 4 }}>
            Leave empty to rank existing candidate submissions. Supports PDF and TXT files.
          </p>
        </div>

        {uploadedFiles.length > 0 && (
          <div style={{ marginBottom: 16, padding: 12, background: 'var(--gray-50)', borderRadius: 8 }}>
            <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-700)', marginBottom: 8 }}>
              Selected Files ({uploadedFiles.length}):
            </div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {uploadedFiles.map((file, index) => (
                <Badge key={index} color="blue">{file.name}</Badge>
              ))}
            </div>
          </div>
        )}

        {/* Rank Button */}
        <Btn
          onClick={handleRankCVs}
          disabled={rankingLoading || !selectedJob}
          style={{ minWidth: 160 }}
        >
          {rankingLoading ? (
            <><Spinner size={16} />&nbsp;Analyzing CVs...</>
          ) : (
            <><svg width="16" height="16" fill="none" stroke="#fff" strokeWidth="2.5" viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg>&nbsp;Rank CVs</>
          )}
        </Btn>
      </div>

      {/* Rankings Table */}
      {rankings.length > 0 && (
        <div style={{ marginTop: 20 }}>
          <h2>Ranked Candidates</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: '#f0f0f0' }}>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Rank</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Candidate</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Final Score</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Similarity</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Skill Match</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Matched Skills</th>
                <th style={{ padding: 8, border: '1px solid #ddd' }}>Evidence</th>
              </tr>
            </thead>
            <tbody>
              {rankings.map((rank, index) => (
                <tr key={rank.submission_id || rank.file_name}>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{index + 1}</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.candidate_name || rank.file_name}</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.final_score}%</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.similarity_score}%</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>{rank.skill_match_pct}%</td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>
                    {rank.matched_skills && rank.matched_skills.length > 0 ? (
                      rank.matched_skills.map(skill => (
                        <Badge key={skill} color="green">{skill}</Badge>
                      ))
                    ) : 'None'}
                  </td>
                  <td style={{ padding: 8, border: '1px solid #ddd' }}>
                    {rank.evidence && rank.evidence.length > 0 ? rank.evidence.join(' | ') : 'None'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {loading && <Spinner />}
    </div>
  );
}
